func spiralMatrix(matrix [][]int) []int {
	if len(matrix) == 0 {
		return []int{}
	}

	rows := len(matrix)
	columns := len(matrix[0])
	result := make([]int, 0, rows*columns)

	topRow := 0
	bottomRow := rows - 1
	leftColumn := 0
	rightColumn := columns - 1

	direction := 0 // 0: right, 1: down, 2: left, 3: up

	for topRow <= bottomRow && leftColumn <= rightColumn {
		switch direction {
		case 0:
			// Traverse right
			for i := leftColumn; i <= rightColumn; i++ {
				result = append(result, matrix[topRow][i])
			}
			topRow++
			direction = 1 // Change to down

		case 1:
			// Traverse down
			for i := topRow; i <= bottomRow; i++ {
				result = append(result, matrix[i][rightColumn])
			}
			rightColumn--
			direction = 2 // Change to left

		case 2:
			// Traverse left
			for i := rightColumn; i >= leftColumn; i-- {
				result = append(result, matrix[bottomRow][i])
			}

			// Update bottom bound, preparation for next layer.
			bottomRow--
			direction = 3 // Change to up

		case 3:
			// Traverse up
			for i := bottomRow; i >= topRow; i-- {
				result = append(result, matrix[i][leftColumn])
			}
			// Update left bound, preparing for next layer.
			leftColumn++
			direction = 0 // Change to right
		}
