public class SpiralMatrix {

    public int[] spiralOrder(int[][] matrix) {
        if (matrix == null || matrix.length == 0) {
            return new int[0];
        }

        int rows = matrix.length;
        int columns = matrix[0].length;
        int[] result = new int[rows * columns];
        int resultIndex = 0;

        int top = 0;
        int bottom = rows - 1;
        int left = 0;
        int right = columns - 1;

        // Continue as long as there are layers to traverse
        while (top <= bottom && left <= right) {

            // Traverse top row from left to right
            for (int i = left; i <= right; i++) {
                result[resultIndex++] = matrix[top][i];
            }
            top++;

            // Traverse right column from top to bottom
            for (int i = top; i <= bottom; i++) {
                result[resultIndex++] = matrix[right][i];
            }
            right--;

            // Make sure that top and left have not crossed bottom and right
            if (top <= bottom) {
                // Traverse bottom row from right to left
                for (int i = right; i >= left; i--) {
                    result[resultIndex++] = matrix[bottom][i];
                }
                bottom--;
            }

            // Make sure that top and left have not crossed bottom and right
            if (left <= right) {

                // Traverse left column from bottom to top
                for (int i = bottom; i >= top; i--) {
                    result[resultIndex++] = matrix[left][i];
                }
                left++;
            }
        }

