        	// Traverse left, adding elements from the bottom row
            for column in stride(from: endColumnIndex, through: startColumnIndex, by: -1) {
                result.append(matrix[endRowIndex][column])
            }

        	endRowIndex -= 1
        }

        // Ensures no double-counting if it's a single row or column
        if startColumnIndex <= endColumnIndex {
        	// Traverse up, adding elements from the leftmost column
            for row in stride(from: endRowIndex, through: startRowIndex, by: -1) {
                result.append(matrix[row][startColumnIndex])
            }

        	startColumnIndex += 1
        }
    }

    return result
}
